def _get_current_faiss_paths(
    *,
    faiss_node_key: str | None,
    node_map_payload: Dict[str, Any],
    chat_history_payload: Dict[str, Any],
) -> List[str]:
    if not faiss_node_key:
        return []

    entry = chat_history_payload.get(faiss_node_key)
    if isinstance(entry, dict) and entry.get("faiss_paths") is not None:
        return _normalize_selected_paths(entry.get("faiss_paths"))

    cfg = node_map_payload.get(faiss_node_key, {}) if isinstance(node_map_payload, dict) else {}
    if not isinstance(cfg, dict):
        cfg = {}
    return _normalize_selected_paths(cfg.get("faiss_paths", cfg.get("faiss_folder")))

def _set_faiss_paths(
    *,
    faiss_node_key: str,
    selected_paths: List[str],
    node_map_payload: Dict[str, Any],
    chat_history_payload: Dict[str, Any],
) -> None:
    if not faiss_node_key:
        return

    cfg = node_map_payload.get(faiss_node_key, {})
    if not isinstance(cfg, dict):
        cfg = {}
    cfg["faiss_folder"] = list(selected_paths)
    cfg["faiss_paths"] = list(selected_paths)
    node_map_payload[faiss_node_key] = cfg

    entry = chat_history_payload.get(faiss_node_key)
    if not isinstance(entry, dict):
        entry = {}
        chat_history_payload[faiss_node_key] = entry
    entry.setdefault("type", "FaissStore")
    entry["faiss_paths"] = list(selected_paths)
    if cfg.get("index") is not None or entry.get("index") is not None:
